import create from 'zustand';

/**
 * @typedef {Object} CodeBlock
 * @property {string} id - Unique identifier for the code block.
 * @property {string} code - The actual code as a string.
 */

/**
 * @typedef {Object} StoreState
 * @property {CodeBlock[]} codeBlocks - The list of code blocks to be managed.
 * @property {Function} addCodeBlock - Function to add a new code block.
 * @property {Function} removeCodeBlock - Function to remove a code block by id.
 * @property {Function} optimizeCode - Function to optimize the current code blocks.
 */

/**
 * Zustand store for managing code blocks.
 */
const useStore = create((set) => ({
  codeBlocks: [],
  addCodeBlock: (code) => set((state) => ({
    codeBlocks: [...state.codeBlocks, { id: Date.now().toString(), code }]
  })),
  removeCodeBlock: (id) => set((state) => ({
    codeBlocks: state.codeBlocks.filter(block => block.id !== id)
  })),
  optimizeCode: async () => {
    try {
      const response = await fetch('http://localhost:3001/optimize', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ codeBlocks: useStore.getState().codeBlocks })
      });
      if (!response.ok) throw new Error('Failed to optimize code');
      const optimizedCode = await response.json();
      set({ codeBlocks: optimizedCode });
    } catch (error) {
      console.error('Error optimizing code:', error);
    }
  }
}));

/**
 * @function pruneUnusedCode
 * @description Prunes unused code blocks from the store.
 */
export async function pruneUnusedCode() {
  try {
    const response = await fetch('http://localhost:3001/prune', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ codeBlocks: useStore.getState().codeBlocks })
    });
    if (!response.ok) throw new Error('Failed to prune code');
    const prunedCode = await response.json();
    useStore.setState({ codeBlocks: prunedCode });
  } catch (error) {
    console.error('Error pruning unused code:', error);
  }
}

/**
 * @function fetchAIOptimization
 * @description Fetches AI-assisted optimization suggestions.
 */
export async function fetchAIOptimization() {
  try {
    const response = await fetch('http://localhost:3001/chat', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ codeBlocks: useStore.getState().codeBlocks })
    });
    if (!response.ok) throw new Error('Failed to fetch AI optimization');
    const suggestions = await response.json();
    return suggestions;
  } catch (error) {
    console.error('Error fetching AI optimization:', error);
    return null;
  }
}

/**
 * @function getCodeBlocks
 * @description Gets the current list of code blocks from the store.
 * @returns {CodeBlock[]} The current code blocks.
 */
export function getCodeBlocks() {
  return useStore.getState().codeBlocks;
}

/**
 * @function clearCodeBlocks
 * @description Clears all code blocks from the store.
 */
export function clearCodeBlocks() {
  useStore.setState({ codeBlocks: [] });
}

export { useStore };